import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

HistoryEntry _makeEntry(String id, {String moduleId = 'mandelbrot'}) {
  return HistoryEntry(
    id: id,
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    params: {},
    visitedAt: DateTime.utc(2024, 1, 1),
  );
}

void main() {
  group('HistoryStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await HistoryStore.create();
      expect(store, isNotNull);
    });

    test('loadHistory returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('saveHistory and loadHistory round-trip entries', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('1', moduleId: 'mandelbrot'),
        _makeEntry('2', moduleId: 'julia'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(2));
      expect(loaded[0].id, equals('1'));
      expect(loaded[0].moduleId, equals('mandelbrot'));
      expect(loaded[1].id, equals('2'));
      expect(loaded[1].moduleId, equals('julia'));
    });

    test('history entries maintain insertion order', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('first', moduleId: 'mandelbrot'),
        _makeEntry('second', moduleId: 'julia'),
        _makeEntry('third', moduleId: 'burning_ship'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(3));
      expect(loaded[0].id, equals('first'));
      expect(loaded[1].id, equals('second'));
      expect(loaded[2].id, equals('third'));
    });

    test('saveHistory caps oldest-first history to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
          _makeEntry('history_$i'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(HistoryStore.maxHistoryEntries));
      expect(loaded.first.id, 'history_2');
      expect(loaded.last.id, 'history_${HistoryStore.maxHistoryEntries + 1}');
    });

    test('loadFavorites returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadFavorites(), isEmpty);
    });

    test('addFavorite appends entry to favorites', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav1'));
    });

    test('addFavorite does not duplicate existing entry', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
    });

    test('saveFavorites caps oldest-first favorites to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
          _makeEntry('favorite_$i'),
      ];

      await store.saveFavorites(entries);
      final loaded = store.loadFavorites();

      expect(loaded, hasLength(HistoryStore.maxFavoriteEntries));
      expect(loaded.first.id, 'favorite_2');
      expect(loaded.last.id, 'favorite_${HistoryStore.maxFavoriteEntries + 1}');
    });

    test('removeFavorite removes entry by ID', () async {
      final store = await HistoryStore.create();
      await store.addFavorite(_makeEntry('fav1'));
      await store.addFavorite(_makeEntry('fav2'));

      await store.removeFavorite('fav1');
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav2'));
    });

    test('clearHistory removes all history', () async {
      final store = await HistoryStore.create();
      await store.saveHistory([_makeEntry('1'), _makeEntry('2')]);

      await store.clearHistory();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory handles corrupted JSON gracefully', () async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': 'not valid json {{{',
      });
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory skips corrupted individual entries', () async {
      // Valid JSON array but one entry has missing required fields.
      SharedPreferences.setMockInitialValues({
        'exploration_history':
            '[{"id":"1","moduleId":"mandelbrot","view":{"panX":0,"panY":0,"zoom":1,"rotX":0,"rotY":0,"rotZ":0},"params":{},"visitedAt":"2024-01-01T00:00:00.000Z"},{"bad":"entry"}]',
      });
      final store = await HistoryStore.create();
      final loaded = store.loadHistory();
      // The valid entry should be present; the corrupted one silently skipped.
      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('1'));
    });
  });
}

import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

/// Creates an immutable-by-convention history snapshot of a mutable view state.
///
/// [FractalViewState] stores mutable vector_math objects, so history must clone
/// those vectors at the record boundary to keep debounced writes replayable.
FractalViewState snapshotHistoryView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

/// Creates a deep JSON-like snapshot of parameters at the record boundary.
Map<String, Object> snapshotHistoryParams(Map<String, Object> params) {
  return {
    for (final entry in params.entries)
      entry.key: snapshotHistoryParamValue(entry.value),
  };
}

/// Deep-copies JSON-like parameter values so history replay is not affected by
/// later mutations of nested list/map values owned by controllers or widgets.
///
/// Nested map keys are normalized to strings because history entries are
/// persisted as JSON objects. Without this, a controller-owned metadata map
/// with enum/int keys can make the whole history save fail during jsonEncode.
Object snapshotHistoryParamValue(Object value) {
  if (value is List) {
    return [
      for (final item in value)
        item is Object ? snapshotHistoryParamValue(item) : item,
    ];
  }

  if (value is Map) {
    return {
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? snapshotHistoryParamValue(entry.value as Object)
            : entry.value,
    };
  }

  return value;
}

/// Pure location-equivalence contract for history de-duplication.
///
/// A history location is the restorable fractal state: module, view, and
/// parameters. Metadata such as entry id, favorite name, and timestamp is not
/// part of location identity.
bool isSameHistoryLocation({
  required String moduleId,
  required FractalViewState view,
  required Map<String, Object> params,
  required String otherModuleId,
  required FractalViewState otherView,
  required Map<String, Object> otherParams,
}) {
  if (moduleId != otherModuleId) {
    return false;
  }
  if (view.zoom != otherView.zoom) {
    return false;
  }
  if (view.pan.x != otherView.pan.x || view.pan.y != otherView.pan.y) {
    return false;
  }
  if (view.rotation.x != otherView.rotation.x ||
      view.rotation.y != otherView.rotation.y ||
      view.rotation.z != otherView.rotation.z) {
    return false;
  }
  return haveSameHistoryParams(params, otherParams);
}

/// Compares history parameter snapshots without relying on map iteration order.
bool haveSameHistoryParams(
  Map<String, Object> params,
  Map<String, Object> otherParams,
) {
  if (params.length != otherParams.length) {
    return false;
  }

  for (final entry in params.entries) {
    if (!otherParams.containsKey(entry.key)) {
      return false;
    }
    if (!areSameHistoryParamValue(entry.value, otherParams[entry.key])) {
      return false;
    }
  }

  return true;
}

/// Compares JSON-like history parameter values by value rather than identity.
///
/// Persisted params can contain nested lists/maps after JSON decode. Dart's
/// collection equality is identity-based, which would make two replayed
/// locations look different even when their serialized parameter values match.
bool areSameHistoryParamValue(Object? value, Object? otherValue) {
  if (identical(value, otherValue)) return true;

  if (value is List && otherValue is List) {
    if (value.length != otherValue.length) return false;
    for (var i = 0; i < value.length; i++) {
      if (!areSameHistoryParamValue(
          value[i] as Object?, otherValue[i] as Object?)) {
        return false;
      }
    }
    return true;
  }

  if (value is Map && otherValue is Map) {
    if (value.length != otherValue.length) return false;
    for (final entry in value.entries) {
      if (!otherValue.containsKey(entry.key)) return false;
      if (!areSameHistoryParamValue(
        entry.value as Object?,
        otherValue[entry.key] as Object?,
      )) {
        return false;
      }
    }
    return true;
  }

  return value == otherValue;
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Result of applying a history-list mutation.
class HistoryWindow {
  /// History entries in display order (oldest first).
  final List<HistoryEntry> entries;

  /// Current selected index into [entries], or -1 when empty.
  final int currentIndex;

  const HistoryWindow({
    required this.entries,
    required this.currentIndex,
  });
}

/// Restored history and favorite lists after applying in-memory caps.
class HistoryRestoreSnapshot {
  final List<HistoryEntry> history;
  final int currentIndex;
  final List<HistoryEntry> favorites;

  const HistoryRestoreSnapshot({
    required this.history,
    required this.currentIndex,
    required this.favorites,
  });

  HistoryEntry? get currentEntry =>
      currentIndex >= 0 && currentIndex < history.length
          ? history[currentIndex]
          : null;
}

/// Pure storage-restore policy shared by provider boot and tests.
///
/// Storage writes are capped, but older/corrupted preferences can still contain
/// too many entries. Normalize immediately so first-frame UI state matches the
/// same bounded contract as persisted writes.
class HistoryRestorePolicy {
  const HistoryRestorePolicy._();

  static HistoryRestoreSnapshot restore({
    required List<HistoryEntry> history,
    required List<HistoryEntry> favorites,
    required int maxHistoryEntries,
    required int maxFavoriteEntries,
  }) {
    assert(maxHistoryEntries > 0);
    assert(maxFavoriteEntries > 0);

    final restoredHistory = _mostRecent(history, maxHistoryEntries);
    return HistoryRestoreSnapshot(
      history: restoredHistory,
      currentIndex: restoredHistory.isEmpty ? -1 : restoredHistory.length - 1,
      favorites: _mostRecent(favorites, maxFavoriteEntries),
    );
  }

  static List<HistoryEntry> _mostRecent(
    List<HistoryEntry> entries,
    int maxEntries,
  ) {
    if (entries.length <= maxEntries) return List<HistoryEntry>.of(entries);
    return entries.sublist(entries.length - maxEntries);
  }
}

/// Pure history append policy shared by recording and tests.
///
/// The in-memory provider must enforce the same maximum depth as persistence;
/// otherwise entries silently disappear only after app restart.
class HistoryWindowPolicy {
  const HistoryWindowPolicy._();

  static HistoryWindow append({
    required List<HistoryEntry> entries,
    required int currentIndex,
    required HistoryEntry entry,
    required int maxEntries,
  }) {
    assert(maxEntries > 0);

    final nextEntries = currentIndex >= 0 && currentIndex < entries.length - 1
        ? entries.sublist(0, currentIndex + 1)
        : List<HistoryEntry>.of(entries);

    nextEntries.add(entry);

    if (nextEntries.length > maxEntries) {
      nextEntries.removeRange(0, nextEntries.length - maxEntries);
    }

    return HistoryWindow(
      entries: nextEntries,
      currentIndex: nextEntries.length - 1,
    );
  }
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Pure favorite-list append policy shared by provider mutations.
///
/// Persistence caps favorites to keep local storage bounded. The provider must
/// apply the same cap before notifying listeners so in-memory UI state and the
/// next app launch agree about which favorites still exist.
class HistoryFavoritesPolicy {
  const HistoryFavoritesPolicy._();

  static List<HistoryEntry> append({
    required List<HistoryEntry> favorites,
    required HistoryEntry favorite,
    required int maxFavorites,
  }) {
    assert(maxFavorites > 0);

    final nextFavorites = List<HistoryEntry>.of(favorites)..add(favorite);
    if (nextFavorites.length > maxFavorites) {
      nextFavorites.removeRange(0, nextFavorites.length - maxFavorites);
    }
    return nextFavorites;
  }
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x) from the public `juliaX` URL alias.
  final double? juliaX;

  /// Julia set imaginary constant (c.y) from the public `juliaY` URL alias.
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    _DeepLinkJuliaConstantParams.addRuntimeParams(
      params,
      real: juliaX,
      imaginary: juliaY,
    );

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
enum _DeepLinkRouteKind {
  customSchemeView,
  universalLinkView,
  rejected,
}

/// Normalized custom-scheme route shape.
///
/// `fractalforge://view?...` uses `view` as URI authority/host, while
/// `fractalforge:/view?...` and `fractalforge:view?...` are path-only forms.
/// Keep those shapes distinct so a non-view authority cannot smuggle a view
/// route through its path (for example `fractalforge://other/view?...`).
class _DeepLinkCustomRouteShape {
  final String host;
  final String path;

  const _DeepLinkCustomRouteShape({
    required this.host,
    required this.path,
  });

  factory _DeepLinkCustomRouteShape.fromUri(Uri uri) {
    return _DeepLinkCustomRouteShape(host: uri.host, path: uri.path);
  }

  bool get hasAuthority => host.isNotEmpty;

  bool get isViewRoute {
    if (hasAuthority) {
      return host == DeepLinkService.host && (path.isEmpty || path == '/');
    }
    return path == '/${DeepLinkService.host}' || path == DeepLinkService.host;
  }
}

class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final _DeepLinkRouteKind kind;

  const _DeepLinkRoute._(this.kind);

  bool get isAccepted => kind != _DeepLinkRouteKind.rejected;

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(
        _isCustomViewRoute(uri)
            ? _DeepLinkRouteKind.customSchemeView
            : _DeepLinkRouteKind.rejected,
      );
    }

    if (uri.scheme == 'https' && allowedWebHosts.contains(uri.host)) {
      return _DeepLinkRoute._(
        _isWebViewRoute(uri)
            ? _DeepLinkRouteKind.universalLinkView
            : _DeepLinkRouteKind.rejected,
      );
    }

    return const _DeepLinkRoute._(_DeepLinkRouteKind.rejected);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return _DeepLinkCustomRouteShape.fromUri(uri).isViewRoute;
  }

  static bool _isWebViewRoute(Uri uri) {
    return uri.path == '/${DeepLinkService.host}';
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static final recognizedNames = {
    'type',
    for (final param in DeepLinkService._allQueryParams) param.name,
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
    if (duplicatedRecognizedKeys.isNotEmpty) {
      throw FormatException(
        'Duplicate deep-link query parameter: '
        '${duplicatedRecognizedKeys.first.key}',
      );
    }

    return _DeepLinkQuery._(uri.queryParameters);
  }

  String? operator [](String name) => _params[name];
}

abstract interface class _DeepLinkQueryParamContract {
  String get name;
}

class _BoundedDoubleQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final double min;
  final double max;

  const _BoundedDoubleQueryParam(this.name, this.min, this.max);

  double? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedDouble(query[name], min, max, name);
  }

  String? format(Object? value, {bool preservePrecision = false}) {
    final parsed = DeepLinkService._tryFiniteDouble(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return DeepLinkService._formatDouble(
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  bool _contains(double value) => value >= min && value <= max;
}

class _BoundedIntQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final int min;
  final int max;

  const _BoundedIntQueryParam(this.name, this.min, this.max);

  int? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedInt(query[name], min, max, name);
  }

  String? format(Object? value) {
    final parsed = _DeepLinkIntegerValue.tryParse(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return parsed.toString();
  }

  bool _contains(int value) => value >= min && value <= max;
}

class _DeepLinkIntegerValue {
  static const double _maxSafeIntegerDouble = 9007199254740991.0;

  const _DeepLinkIntegerValue._();

  /// Mirrors runtime module int-param readers for generated links: persisted
  /// parameter maps may carry slider-originated doubles, but generated URLs
  /// must contain replayable integer query values.
  static int? tryParse(Object? value) {
    return switch (value) {
      int v => v,
      double v when _isSafeIntegerDouble(v) => v.round(),
      _ => null,
    };
  }

  static bool _isSafeIntegerDouble(double value) {
    return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
  }
}

/// Mapping between public deep-link Julia aliases and runtime module params.
///
/// Share URLs use compact, stable query names (`juliaX`/`juliaY`), while
/// render modules expose controls as `juliaCReal`/`juliaCImag`. Keeping the
/// mapping explicit prevents generated links and applied deep links from
/// silently dropping Julia constants.
class _DeepLinkJuliaConstantParams {
  static const String urlReal = 'juliaX';
  static const String urlImaginary = 'juliaY';
  static const String runtimeReal = 'juliaCReal';
  static const String runtimeImaginary = 'juliaCImag';

  const _DeepLinkJuliaConstantParams._();

  static void addRuntimeParams(
    Map<String, Object> params, {
    required double? real,
    required double? imaginary,
  }) {
    if (real != null) params[runtimeReal] = real;
    if (imaginary != null) params[runtimeImaginary] = imaginary;
  }

  /// Generated links should prefer actual runtime parameter names but still
  /// accept already URL-shaped maps for compatibility with existing callers.
  static Object? realValueForBuild(Map<String, Object> params) {
    return params[runtimeReal] ?? params[urlReal];
  }

  static Object? imaginaryValueForBuild(Map<String, Object> params) {
    return params[runtimeImaginary] ?? params[urlImaginary];
  }
}

class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  static const _zoomParam = _BoundedDoubleQueryParam('zoom', 0.001, 1e15);
  static const _xParam = _BoundedDoubleQueryParam('x', -1e10, 1e10);
  static const _yParam = _BoundedDoubleQueryParam('y', -1e10, 1e10);
  static const _rotXParam = _BoundedDoubleQueryParam('rotX', -1e10, 1e10);
  static const _rotYParam = _BoundedDoubleQueryParam('rotY', -1e10, 1e10);
  static const _rotZParam = _BoundedDoubleQueryParam('rotZ', -1e10, 1e10);
  static const _iterationsParam = _BoundedIntQueryParam('iterations', 1, 10000);
  static const _bailoutParam = _BoundedDoubleQueryParam('bailout', 1.0, 1e10);
  static const _colorSchemeParam =
      _BoundedIntQueryParam('colorScheme', 0, 9999);
  static const _powerParam = _BoundedDoubleQueryParam('power', 1, 20);
  static const _juliaXParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlReal,
    -1e10,
    1e10,
  );
  static const _juliaYParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlImaginary,
    -1e10,
    1e10,
  );

  static const List<_DeepLinkQueryParamContract> _allQueryParams = [
    _zoomParam,
    _xParam,
    _yParam,
    _rotXParam,
    _rotYParam,
    _rotZParam,
    _iterationsParam,
    _bailoutParam,
    _colorSchemeParam,
    _powerParam,
    _juliaXParam,
    _juliaYParam,
  ];

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks =
        bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final Object? initialUri = await _channel.invokeMethod('getInitialLink');
      final data = parseIncomingLink(initialUri);
      if (data != null) {
        _initialLink = data;
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final data = parseIncomingLink(call.arguments);
      if (data != null) {
        _linkController.add(data);
      }
    }
  }

  /// Parses a platform-provided deep-link payload into [DeepLinkData].
  ///
  /// Native channels are expected to send URI strings, but malformed payloads
  /// are ignored instead of crashing the method-channel handler.
  static DeepLinkData? parseIncomingLink(
    Object? link, {
    List<String>? validFractalTypes,
  }) {
    if (link is! String || link.isEmpty) {
      return null;
    }

    try {
      return parseUri(
        Uri.parse(link),
        validFractalTypes: validFractalTypes,
      );
    } catch (e) {
      // Malformed URI, ignore.
      if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      return null;
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    final route = _DeepLinkRoute.fromUri(uri);
    if (!route.isAccepted) {
      return null;
    }

    final _DeepLinkQuery query;
    try {
      query = _DeepLinkQuery.fromUri(uri);
    } on FormatException catch (e) {
      if (kDebugMode) debugPrint('DeepLink: ${e.message} — rejecting link');
      return null;
    }

    final type = query['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth).
    if (!_DeepLinkModuleId.isSafe(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _zoomParam.parse(query),
      x: _xParam.parse(query),
      y: _yParam.parse(query),
      rotX: _rotXParam.parse(query),
      rotY: _rotYParam.parse(query),
      rotZ: _rotZParam.parse(query),
      iterations: _iterationsParam.parse(query),
      bailout: _bailoutParam.parse(query),
      colorScheme: _colorSchemeParam.parse(query),
      power: _powerParam.parse(query),
      juliaX: _juliaXParam.parse(query),
      juliaY: _juliaYParam.parse(query),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': _DeepLinkModuleId.requireSafeForBuild(moduleId),
    };

    // Add view state. Use the same bounded contracts as parsing so generated
    // links do not round-trip through clamped or invalid camera values.
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _zoomParam,
      view.zoom,
      defaultValue: 1.0,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _xParam,
      view.pan.x,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _yParam,
      view.pan.y,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotXParam, view.rotation.x);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotYParam, view.rotation.y);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotZParam, view.rotation.z);

    // Add fractal parameters. Unsupported values are omitted rather than
    // converted to sentinel values that parse back as valid-but-wrong params.
    _addBoundedIntQueryParam(
        queryParams, _iterationsParam, params['iterations']);
    _addBoundedDoubleQueryParam(queryParams, _bailoutParam, params['bailout']);
    _addBoundedIntQueryParam(
      queryParams,
      _colorSchemeParam,
      params['colorScheme'],
    );
    _addBoundedDoubleQueryParam(queryParams, _powerParam, params['power']);
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaXParam,
      _DeepLinkJuliaConstantParams.realValueForBuild(params),
      preservePrecision: true,
    );
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaYParam,
      _DeepLinkJuliaConstantParams.imaginaryValueForBuild(params),
      preservePrecision: true,
    );

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    if (!preservePrecision || double.tryParse(compactFixed) == value) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/deep_link_service.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepLinkService', () {
    group('parseIncomingLink', () {
      test('parses string payloads from platform channels', () {
        final data = DeepLinkService.parseIncomingLink(
          'fractalforge://view?type=mandelbrot&zoom=5',
        );

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('ignores malformed or non-string platform payloads', () {
        expect(DeepLinkService.parseIncomingLink(null), isNull);
        expect(DeepLinkService.parseIncomingLink(42), isNull);
        expect(DeepLinkService.parseIncomingLink(''), isNull);
        expect(
          DeepLinkService.parseIncomingLink('fractalforge://view?type=%'),
          isNull,
        );
      });
    });

    group('parseUri', () {
      test('parses basic fractalforge:// URL', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
      });

      test('parses URL with zoom and pan parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 10.0);
        expect(data.x, -0.5);
        expect(data.y, 0.1);
      });

      test('parses URL with 3D rotation parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&rotZ=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.rotX, 0.5);
        expect(data.rotY, 0.3);
        expect(data.rotZ, 0.1);
      });

      test('parses URL with fractal parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=julia&iterations=200&colorScheme=2&juliaX=-0.7&juliaY=0.27');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'julia');
        expect(data.iterations, 200);
        expect(data.colorScheme, 2);
        expect(data.juliaX, -0.7);
        expect(data.juliaY, 0.27);
      });

      test('returns null for non-fractalforge scheme', () {
        final uri = Uri.parse('https://example.com/view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('returns null for missing type parameter', () {
        final uri = Uri.parse('fractalforge://view?zoom=10');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('parses https://fractalforge.app universal link', () {
        final uri =
            Uri.parse('https://fractalforge.app/view?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('characterizes accepted deep-link route variants', () {
        final acceptedLinks = [
          'fractalforge://view?type=mandelbrot',
          'fractalforge://view/?type=mandelbrot',
          'fractalforge:/view?type=mandelbrot',
          'fractalforge:view?type=mandelbrot',
          'https://fractalforge.app/view?type=mandelbrot',
          'https://www.fractalforge.app/view?type=mandelbrot',
        ];

        for (final link in acceptedLinks) {
          expect(
            DeepLinkService.parseUri(Uri.parse(link))?.type,
            'mandelbrot',
            reason: link,
          );
        }
      });

      test('rejects custom-scheme route authority/path ambiguity', () {
        final rejectedLinks = [
          'fractalforge://other/view?type=mandelbrot',
          'fractalforge://view/settings?type=mandelbrot',
          'fractalforge://view/view?type=mandelbrot',
        ];

        for (final link in rejectedLinks) {
          expect(
            DeepLinkService.parseUri(Uri.parse(link)),
            isNull,
            reason: link,
          );
        }
      });

      test('rejects https universal links outside the view route', () {
        final uri = Uri.parse(
            'https://fractalforge.app/settings?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate recognized parameters instead of guessing', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&type=julia&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate optional parameters instead of truncating', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&zoom=5&zoom=abc',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('ignores duplicate unrecognized parameters', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&utm=a&utm=b&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('rejects duplicates for every generated deep-link parameter', () {
        final generated = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: const {
            'iterations': 200,
            'bailout': 4.5,
            'colorScheme': 2,
            'power': 8.0,
            'juliaX': -0.7,
            'juliaY': 0.27,
          },
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 5.0,
            rotation: Vector3(0.1, 0.2, 0.3),
          ),
        );

        for (final paramName in generated.queryParameters.keys) {
          final duplicated = generated.replace(
            query: '${generated.query}&$paramName=duplicate',
          );

          expect(
            DeepLinkService.parseUri(duplicated),
            isNull,
            reason: '$paramName must be part of duplicate detection',
          );
        }
      });
    });

    group('buildUri', () {
      test('builds basic URL with type only', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'fractalforge');
        expect(uri.host, 'view');
        expect(uri.queryParameters['type'], 'mandelbrot');
      });

      test('rejects unsafe module IDs before generating unreplayable links',
          () {
        expect(
          () => DeepLinkService.buildUri(
            moduleId: 'mandelbrot<script>',
            params: const {},
            view: FractalViewState.initial(),
          ),
          throwsArgumentError,
        );
      });

      test('includes zoom when not default', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 5.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['zoom'], '5');
      });

      test('includes pan coordinates when not zero', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 1.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['x'], '-0.5');
        expect(uri.queryParameters['y'], '0.25');
      });

      test('includes rotation for 3D fractals', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbulb',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 1.0,
            rotation: Vector3(0.5, 0.3, 0.1),
          ),
        );

        expect(uri.queryParameters['rotX'], '0.5');
        expect(uri.queryParameters['rotY'], '0.3');
        expect(uri.queryParameters['rotZ'], '0.1');
      });

      test('includes fractal parameters', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 200,
            'colorScheme': 2,
            'bailout': 4.5,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '200');
        expect(uri.queryParameters['colorScheme'], '2');
        expect(uri.queryParameters['bailout'], '4.5');
      });

      test('uses runtime Julia parameter names when building URL aliases', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: {
            'juliaCReal': -0.7,
            'juliaCImag': 0.27015,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['juliaX'], '-0.7');
        expect(uri.queryParameters['juliaY'], '0.27015');
      });

      test('formats finite double-valued integer params like runtime readers',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 120.5,
            'colorScheme': 2.0,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '121');
        expect(uri.queryParameters['colorScheme'], '2');
      });

      test('omits unsupported parameter values instead of minting fallbacks',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': true,
            'colorScheme': Object(),
