/// Safe parameter readers for uniform setters.
const double _maxSafeIntegerDouble = 9007199254740991.0;

bool _isSafeIntegerDouble(double value) {
  return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
}

double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double && value.isFinite) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double && _isSafeIntegerDouble(value)) return value.round();
  return fallback;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Common parameter builders shared across many 2D modules.
///
/// Keep these helpers small and stable; they are used in tests and codegen later.
class CommonFractalParams {
  static const int paletteCount = 64;

  static FractalParameter iterations({
    required num defaultValue,
    num min = 20,
    num max = 5000,
  }) {
    return FractalParameter(
      id: 'iterations',
      label: (l10n) => l10n.paramIterations,
      type: FractalParamType.integer,
      min: min.toDouble(),
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter bailout({
    required double defaultValue,
    double min = 2.0,
    double max = 8.0,
  }) {
    return FractalParameter(
      id: 'bailout',
      label: (l10n) => l10n.paramBailout,
      type: FractalParamType.float,
      min: min,
      max: max,
      step: 0.1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter colorScheme4({Object defaultValue = 0, num max = 3}) {
    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
      options: [
        FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
        FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
        FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
        FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      ],
    );
  }

  /// Color cycle speed for palette-texture shaders (G15).
  ///
  /// A value of 0.0 = static (no cycling); 0.1 = ~1 full cycle every 10 s.
  /// Only meaningful at deep zoom where the perturbation shader is active
  /// (zoom >= 5e6). The controls panel shows this slider for all modules that
  /// include it, but it only has visible effect in the perturbation path.
  static FractalParameter colorCycleSpeed() {
    return FractalParameter(
      id: 'colorCycleSpeed',
      label: (l10n) => 'Color speed',
      type: FractalParamType.float,
      min: 0.0,
      max: 0.2,
      step: 0.001,
      defaultValue: 0.0,
    );
  }

  static FractalParameter colorScheme64({int defaultValue = 0}) {
    // Keep the first 4 as named palettes for continuity.
    final options = <FractalParamOption>[
      FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
      FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
      FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
      FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      // Remaining palettes are numbered. Keep labels simple for screen readers.
      // Palette 5 reserved for legacy Phoenix palette name.
      FractalParamOption(value: 4, label: (l10n) => l10n.colorPhoenix),
      for (int i = 5; i < paletteCount; i++)
        FractalParamOption(
          value: i,
          label: (AppLocalizations l10n) => 'Palette ${i + 1}',
        ),
    ];

    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: paletteCount - 1,
      step: 1,
      defaultValue: defaultValue,
      options: options,
    );
  }
}

